import (
	context "context"
	fern "github.com/unions/fern"
	fernclient "github.com/unions/fern/client"
)

client := fernclient.NewClient()
response, err := client.Union.Update(
	context.TODO(),
	fern.NewShapeFromShapeZero(
		&fern.ShapeZero{
			Radius: 1.1,
			Type:   fern.ShapeZeroTypeCircle,
		},
	),
)

